function parseWorkTypes(raw) {
  if (!raw) return [];
  return raw.split(',').map(s => s.trim()).filter(Boolean);
}

function parseTurnover(raw) {
  if (!raw) return undefined;
  const s = raw.toString().replace(/[^0-9.]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? undefined : n;
}

function parseRefs(raw) {
  if (!raw || raw === 'No' || raw === 'NA') return [undefined, undefined];
  const parts = raw.split(',');
  return [parts[0]?.trim() || undefined, parts[1]?.trim() || undefined];
}

function cleanMobile(raw) {
  if (!raw) return '';
  return raw.toString().replace(/\s/g, '').replace(/^\+91/, '').slice(0, 15);
}

