async function run() {
  await mongoose.connect(process.env.MONGO_URI);
  console.log('Connected to MongoDB\n');

  let updated = 0, created = 0;

  for (const v of VENDORS) {
    const [ref1, ref2] = parseRefs(v.references);
    const workTypes = parseWorkTypes(v.workTypes);
    const averageTurnover = parseTurnover(v.averageTurnover);
    const mobile = cleanMobile(v.mobile) || '0000000000';

    const payload = {
      companyName: v.companyName,
      ownerName: v.ownerName,
      address: v.address || '',
      mobile,
      alternateMobile: cleanMobile(v.alternateMobile) || '',
      email: v.email || '',
      accountHolderName: v.accountHolderName || '',
      bankName: v.bankName || '',
      accountNumber: v.accountNumber || '',
      ifscCode: v.ifscCode || '',
      branchName: v.branchName || '',
      gstNumber: v.gstNumber || '',
      panNumber: v.panNumber || '',
      workTypes,
      ...(ref1 && { reference1: ref1 }),
      ...(ref2 && { reference2: ref2 }),
      ...(averageTurnover !== undefined && { averageTurnover }),
    };

    const existing = await Contractor.findOne({ vendorCode: v.vendorCode });
    if (existing) {
      await Contractor.updateOne({ vendorCode: v.vendorCode }, { $set: payload });
      console.log(`UPDATED  ${v.vendorCode} → ${v.companyName}`);
      updated++;
    } else {
      await Contractor.create({ vendorCode: v.vendorCode, ...payload });
      console.log(`CREATED  ${v.vendorCode} → ${v.companyName}`);
      created++;
    }
  }

  console.log(`\nDone — Updated: ${updated} | Created: ${created}`);
  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });
